module RefModule(CLK, RST, Gray);
input CLK, RST;
output [1:0] Gray;
reg [1:0] Gray;
reg [1:0] binary_counter;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge RST or posedge dbg_halt) begin
    if (RST) begin
        binary_counter <= 0;
        Gray <= 0;
    end else begin
        binary_counter <= binary_counter + 1;
        Gray <= (binary_counter >> 1) ^ binary_counter;
    end
end

endmodule
